mapper.sql:
tenant_id = #{tenantId}

    and (lower(name) like concat('%', lower(#{keyword}), '%')
     or lower(code) like concat('%', lower(#{keyword}), '%')
     or lower(endpoint) like concat('%', lower(#{keyword}), '%'))

and type = #{type}
and env_id = #{envId}
and region_id = #{regionId}
and connection_status = #{status}

mapper.update:
update fp_infrastructure
set type = #{type}, code = #{code}, name = #{name}, env_id = #{envId}, region_id = #{regionId},
    endpoint = #{endpoint}, auth_type = #{authType}, username = #{username}, password = #{password},
    api_key = #{apiKey}, sync_scope = #{syncScope}, sync_mode = #{syncMode}, sync_enabled = #{syncEnabled},
    sync_interval_sec = #{syncIntervalSec}, description = #{description}, updated_at = #{updatedAt}
where tenant_id = #{tenantId} and id = #{id}

update fp_infrastructure
set run_status = #{runStatus}, connection_status = #{connectionStatus},
    last_test_message = #{lastTestMessage}, last_test_at = #{lastTestAt},
    last_sync_at = #{lastSyncAt}, last_sync_message = #{lastSyncMessage}, updated_at = #{updatedAt}
where tenant_id = #{tenantId} and id = #{id}
